import React from 'react'
import { Link, useNavigate } from 'react-router-dom';

const Nav = () => {
  const navigate = useNavigate();
  const customerId = sessionStorage.getItem("customerid");
  const sellerId = sessionStorage.getItem("sellerid");
  const isLoggedIn = customerId || sellerId;

  const handleLogout = () => {
    sessionStorage.clear();
    navigate('/customer/signin');
  };

  return (
    <div>
      <nav className="navbar navbar-expand-lg bg-primary shadow-success-lg navbar-boarder-warning" data-bs-theme="dark">
        <div className="container-fluid ">
          <Link className="navbar-brand text-success" to="/">Shopping App</Link>
          <button className="navbar-toggler" type="button" data-bs-toggle="collapse" data-bs-target="#navbarNavAltMarkup" aria-controls="navbarNavAltMarkup" aria-expanded="false" aria-label="Toggle navigation">
            <span className="navbar-toggler-icon"></span>
          </button>
          <div className="collapse navbar-collapse" id="navbarNavAltMarkup">
            <div className="navbar-nav ms-auto">
              <Link className="btn   btn-outline-danger text-white rounded-pill px-3 m" to="/view">View All</Link>
              {isLoggedIn ? (
                <>
                  {customerId && <Link className="btn  btn-outline-warning text-light-emphasis  rounded-pill px-3 mr-5" to="/customer/cart">Cart</Link>}
                  {customerId && <Link className="btn  btn-outline-warning text-light-emphasis  rounded-pill px-3 mr-5" to="/customer/vieworders">My Orders</Link>}
                  {sellerId && <Link className="btn  btn-outline-warning text-light-emphasis  rounded-pill px-3 mr-5" to="/seller/addproduct">Add Product</Link>}
                  {sellerId && <Link className="btn  btn-outline-warning text-light-emphasis  rounded-pill px-3 mr-5" to="/seller/vieworders">View Orders</Link>}
                  <button className="btn btn-link nav-link text-light-emphasis bg-danger rounded-pill px-3 " onClick={handleLogout}>Logout</button>
                </>
              ) : (
                <Link className="btn  btn-outline-success text-light-emphasis  rounded-pill px-3 " to="/customer/signin">Signin</Link>
              )}
            </div>
          </div>
        </div>
      </nav>
    </div>
  )
}

export default Nav
